import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class PathTraversalSecureCode {

    public static void main(String[] args) {
        String userInput = "/etc/passwd";
        String directory = "/var/www/files/";

        // Validate user input to prevent directory traversal
        if (!userInput.contains("..")) {
            try {
                File file = new File(directory + userInput);
                if (file.getCanonicalPath().startsWith(directory)) { // Check if the resolved path is within the intended directory
                    if (file.exists()) {
                        byte[] fileContent = Files.readAllBytes(Paths.get(file.getPath()));
                        System.out.println(new String(fileContent));
                    } else {
                        System.out.println("File not found");
                    }
                } else {
                    System.out.println("Invalid path");
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("Invalid input");
        }
    }
}

